<?php require_once __DIR__.'/includes/db.php'; $error=''; $lang=current_lang(); if($_SERVER['REQUEST_METHOD']==='POST'){ $login=trim($_POST['login']??''); $pass=$_POST['password']??''; $st=db()->prepare('SELECT u.*, r.role_name FROM users u JOIN roles r ON r.role_id=u.role_id WHERE u.login=? LIMIT 1'); $st->execute([$login]); $u=$st->fetch(); if($u && (int)$u['is_active']===1 && password_verify($pass,$u['password_hash'])){ $_SESSION['user']=['id'=>$u['user_id'],'login'=>$u['login'],'full_name'=>$u['full_name'],'role'=>$u['role_name']]; header('Location: dashboard.php?lang='.current_lang()); exit; } $error='Неверный логин или пароль'; } ?><!doctype html><html lang="<?=h($lang)?>"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>UAMS — <?=h(tr('login'))?></title><link rel="stylesheet" href="/uams/assets/app.css"></head><body class="auth-page"><form class="auth-card" method="post"><div class="top-actions" style="justify-content:center;margin-bottom:8px"><?php foreach(['ru'=>'RU','kz'=>'KZ','en'=>'EN'] as $k=>$v):?><a class="lang <?=$lang===$k?'active':''?>" href="<?=h(lang_url($k))?>"><?=$v?></a><?php endforeach;?></div><div class="brand-icon" style="margin:0 auto">U</div><h1>UAMS</h1><p class="muted" style="text-align:center"><?=h(tr('app_title'))?></p><?php if($error):?><div class="notice err"><?=h($error)?></div><?php endif;?><label><?=h(tr('login_name'))?></label><input class="input" name="login" value="superadmin" required><label><?=h(tr('password'))?></label><input class="input" type="password" name="password" value="superadmin123" required><button class="btn" type="submit"><?=h(tr('sign_in'))?></button><div class="auth-links"><a href="register.php?lang=<?=h($lang)?>"><?=h(tr('register'))?></a></div><p class="muted" style="text-align:center">superadmin / superadmin123</p></form></body></html>